/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    if (!nums || nums.length === 0) {
        return 0;
    }

    // 1. Extract unique values V
    const uniqueValues = Array.from(new Set(nums));

    // V_set for O(1) lookup
    const V_set = new Set(uniqueValues);

    // 2. Sort V in descending order
    // We need to iterate from largest to smallest to ensure that when calculating Min_V[x], 
    // the Min_V[d] for all divisors d < x are already finalized.
    uniqueValues.sort((a, b) => b - a);

    // 3. Initialize Min_V: Min_V[v] stores the minimum reachable value starting from v
    const Min_V = new Map();
    for (const v of uniqueValues) {
        Min_V.set(v, v);
    }

    // 4. DP calculation
    for (const x of uniqueValues) {
        const currentMin = Min_V.get(x);

        // Find divisors d of x, where d < x
        // Iterate up to sqrt(x)
        const limit = Math.floor(Math.sqrt(x));

        for (let d = 1; d <= limit; d++) {
            if (x % d === 0) {
                // Check divisor d
                if (d < x && V_set.has(d)) {
                    // d is a divisor and d is an initial value
                    const min_d = Min_V.get(d);
                    if (min_d < currentMin) {
                        Min_V.set(x, min_d);
                        currentMin = min_d;
                    }
                }

                // Check conjugate divisor x/d
                const d_conjugate = x / d;
                if (d_conjugate !== d && d_conjugate < x && V_set.has(d_conjugate)) {
                    // d_conjugate is a divisor and d_conjugate is an initial value
                    const min_d_conj = Min_V.get(d_conjugate);
                    if (min_d_conj < currentMin) {
                        Min_V.set(x, min_d_conj);
                        currentMin = min_d_conj;
                    }
                }
            }
        }
    }

    // 5. Calculate the final sum
    let totalSum = 0;
    for (const n of nums) {
        // n must be in V_set, so Min_V.get(n) is safe
        totalSum += Min_V.get(n);
    }

    return totalSum;
}
