function solve(nums) {
    const M = 100000;

    // Step 1: Find unique elements D
    const uniqueNumsSet = new Set(nums);
    const D = Array.from(uniqueNumsSet);

    // Sort D to ensure we process smaller divisors first, which helps in finding the minimum efficiently.
    D.sort((a, b) => a - b);

    // R[i] stores the smallest element d in D such that d divides i.
    // Initialize R[i] = i. This handles the case where i itself is the smallest divisor found in D (or if i is not in D but has no smaller divisor in D).
    const R = new Array(M + 1).fill(0);
    for (let i = 1; i <= M; i++) {
        R[i] = i;
    }

    // Step 2: Sieve-like precomputation
    // Iterate over all unique divisors d present in the original array D
    for (const d of D) {
        if (d > M) continue; 

        // Iterate over all multiples x of d up to M
        for (let x = d; x <= M; x += d) {
            // Since d is increasing, we only need to update R[x] if d is strictly smaller than the current value R[x].
            // Note: Since R[x] was initialized to x, if d < x, d is smaller. 
            // If R[x] was already set by a smaller d' < d, then d >= R[x], and we keep R[x].
            if (d < R[x]) {
                 R[x] = d;
            }
        }
    }

    // Step 3: Calculate the minimum possible sum
    let totalSum = 0;
    for (const x of nums) {
        // The minimum value x can be reduced to is R[x]
        totalSum += R[x];
    }

    return totalSum;
}

