function solve(nums) {
    // Step 1: Create a set D of unique elements for O(1) lookup.
    const D = new Set(nums);

    let totalSum = 0;

    // Step 2 & 3: Iterate over each element x in nums and find its minimum reducible value m_x.
    for (const x of nums) {
        // Initialize m_x to x. x is always reducible to itself, and x is in D.
        let m_x = x;

        const limit = Math.floor(Math.sqrt(x));

        let candidates = [];

        // Iterate through potential divisors d up to sqrt(x)
        for (let d = 1; d <= limit; d++) {
            if (x % d === 0) {
                // Check divisor d
                if (D.has(d)) {
                    candidates.push(d);
                }

                // Check complementary divisor d_prime = x/d
                const d_prime = x / d;
                if (D.has(d_prime)) {
                    candidates.push(d_prime);
                }
            }
        }

        // Determine m_x: the minimum divisor of x found in D.
        if (candidates.length > 0) {
            m_x = Math.min(...candidates);
        }

        // Step 4: Accumulate the minimum possible value for x.
        totalSum += m_x;
    }

    return totalSum;
}

